```typescript
import type { ChannelSetupAdapter } from "openclaw/plugin-sdk/channel-setup";
import type { ChannelSetupWizard } from "openclaw/plugin-sdk/setup";
import {
  createTopLevelChannelDmPolicy,
  createStandardChannelSetupStatus,
  patchTopLevelChannelConfigSection,
} from "openclaw/plugin-sdk/setup";
import { DEFAULT_ACCOUNT_ID } from "openclaw/plugin-sdk/routing";
import {
  hasConfiguredSecretInput,
  normalizeSecretInputString,
} from "openclaw/plugin-sdk/secret-input";
import { resolvePulseBoardAccount } from "./types.js";

const channel = "pulseeboard" as const;

const PULSEEBOARD_SETUP_HELP_LINES = [
  "Provide your PulseBoard API token.",
  "Get your workspace ID from PulseBoard settings.",
  `Docs: /channels/pulseeboard`,
];

export const pulseBoardSetupAdapter: ChannelSetupAdapter = {
  resolveAccountId: () => DEFAULT_ACCOUNT_ID,
  applyAccountName: ({ cfg, name }) =>
    patchTopLevelChannelConfigSection({
      cfg,
      channel,
      patch: name?.trim() ? { name: name.trim() } : {},
    }),
  validateInput: ({ input }) => {
    const typedInput = input as {
      apiToken?: string;
      workspaceId?: string;
    };
    if (!typedInput.apiToken?.trim()) {
      return "PulseBoard requires an API token.";
    }
    if (!typedInput.workspaceId?.trim()) {
      return "PulseBoard requires a workspace ID.";
    }
    return null;
  },
  applyAccountConfig: ({ cfg, input }) => {
    const typedInput = input as {
      apiToken?: string;
      workspaceId?: string;
    };
    return patchTopLevelChannelConfigSection({
      cfg,
      channel,
      enabled: true,
      patch: {
        apiToken: typedInput.apiToken?.trim(),
        workspaceId: typedInput.workspaceId?.trim(),
      },
    });
  },
};

const pulseBoardDmPolicy = createTopLevelChannelDmPolicy({
  label: "PulseBoard",
  channel,
  policyKey: "channels.pulseeboard.dmPolicy",
  allowFromKey: "channels.pulseeboard.allowFrom",
  getCurrent: (cfg) => cfg.channels?.pulseeboard?.dmPolicy ?? "pairing",
  promptAllowFrom: createTopLevelChannelParsedAllowFromPrompt({
    channel,
    defaultAccountId: DEFAULT_ACCOUNT_ID,
    noteTitle: "PulseBoard allowlist",
    noteLines: ["Allowlist PulseBoard users by username or email."],
    message: "PulseBoard allowFrom",
    placeholder: "user@example.com, alice",
    parseEntries: (raw: string) => ({
      entries: raw.split(",").map((e) => e.trim()).filter(Boolean),
    }),
    mergeEntries: ({ existing, parsed }) => [...new Set([...existing, ...parsed])],
  }),
});

export const pulseBoardSetupWizard: ChannelSetupWizard = {
  channel,
  resolveAccountIdForConfigure: () => DEFAULT_ACCOUNT_ID,
  resolveShouldPromptAccountIds: () => false,
  status: createStandardChannelSetupStatus({
    channelLabel: "PulseBoard",
    configuredLabel: "configured",
    unconfiguredLabel: "needs API token",
    configuredHint: "configured",
    unconfiguredHint: "needs API token",
    configuredScore: 1,
    unconfiguredScore: 0,
    includeStatusLine: true,
    resolveConfigured: ({ cfg }) => resolvePulseBoardAccount({ cfg }).configured,
  }),
  introNote: {
    title: "PulseBoard setup",
    lines: PULSEEBOARD_SETUP_HELP_LINES,
  },
  credentials: [
    {
      inputKey: "apiToken",
      providerHint: channel,
      credentialLabel: "API token",
      helpTitle: "PulseBoard API token",
      helpLines: PULSEEBOARD_SETUP_HELP_LINES,
      inputPrompt: "PulseBoard API token",
      keepPrompt: "PulseBoard API token already configured. Keep it?",
      inspect: ({ cfg, accountId }) => {
        const account = resolvePulseBoardAccount({ cfg, accountId });
        return {
          accountConfigured: account.configured,
          hasConfiguredValue: hasConfiguredSecretInput(account.config.apiToken),
          resolvedValue: normalizeSecretInputString(account.config.apiToken),
        };
      },
      applySet: async ({ cfg, resolvedValue }) =>
        patchTopLevelChannelConfigSection({
          cfg,
          channel,
          enabled: true,
          patch: { apiToken: resolvedValue },
        }),
    },
  ],
  textInputs: [
    {
      inputKey: "workspaceId",
      message: "Workspace ID",
      required: true,
      helpTitle: "PulseBoard workspace ID",
      helpLines: ["Find your workspace ID in PulseBoard settings."],
      currentValue: ({ cfg, accountId }) => {
        const account = resolvePulseBoardAccount({ cfg, accountId });
        return account.workspaceId;
      },
      validate: ({ value }) => (!value?.trim() ? "Workspace ID is required" : null),
      applySet: async ({ cfg, value }) =>
        patchTopLevelChannelConfigSection({
          cfg,
          channel,
          enabled: true,
          patch: { workspaceId: value?.trim() },
        }),
    },
  ],
  dmPolicy: pulseBoardDmPolicy,
  disable: (cfg) =>
    patchTopLevelChannelConfigSection({
      cfg,
      channel,
      patch: { enabled: false },
    }),
};
