41	function normalizeGroupEntry(raw: string): string | null {
42	  const trimmed = raw.trim();
43	  if (!trimmed) {
44	    return null;
45	  }
46	  if (trimmed === "*") {
47	    return "*";
48	  }
49	  const normalized = normalizeIrcMessagingTarget(trimmed) ?? trimmed;
50	  if (isChannelTarget(normalized)) {
51	    return normalized;
52	  }
53	  return `#${normalized.replace(/^#+/, "")}`;
54	}
