58	  noteTitle: "IRC allowlist",
59	  noteLines: [
60	    "Allowlist IRC DMs by sender.",
61	    "Examples:",
62	    "- alice",
63	    "- alice!ident@example.org",
64	    "Multiple entries: comma-separated.",
65	  ],
66	  message: "IRC allowFrom (nick or nick!user@host)",
67	  placeholder: "alice, bob!ident@example.org",
68	  parseEntries: (raw) => ({
