/**
 * Type definitions for the PulseBoard channel plugin.
 *
 * PulseBoard is a real-time bulletin board messaging platform. Users post
 * messages to named "boards" (group chats) or send direct messages to other
 * users. Authentication is via an API token tied to a server URL.
 */

/** Config fields shared between the top-level channel config and per-account overrides. */
type PulseBoardConfigFields = {
  enabled?: boolean;
  /** PulseBoard API token for authentication. */
  apiToken?: string;
  /** Base URL of the PulseBoard server (e.g. https://pb.example.com). */
  serverUrl?: string;
  /** DM access policy: "pairing", "allowlist", "open", or "disabled". */
  dmPolicy?: "pairing" | "allowlist" | "open" | "disabled";
  /** Allowed sender usernames or user IDs for DM access control. */
  allowFrom?: Array<string | number>;
  /** Board names to listen on for group messages (e.g. ["general", "ops"]). */
  boards?: string[];
  /** Board (group) access policy: "allowlist" or "open". */
  groupPolicy?: "allowlist" | "open";
};

/** Raw top-level channel config (channels.pulseboard). */
export interface PulseBoardChannelConfig extends PulseBoardConfigFields {
  accounts?: Record<string, PulseBoardAccountRaw>;
}

/** Raw per-account override config. */
export interface PulseBoardAccountRaw extends PulseBoardConfigFields {}

/** Fully resolved account config with all defaults applied. */
export interface ResolvedPulseBoardAccount {
  accountId: string;
  enabled: boolean;
  /** True when both apiToken and serverUrl are present. */
  configured: boolean;
  apiToken: string;
  serverUrl: string;
  dmPolicy: "pairing" | "allowlist" | "open" | "disabled";
  allowFrom: Array<string | number>;
  boards: string[];
  groupPolicy: "allowlist" | "open";
}

/** An inbound message received from PulseBoard. */
