   * Board name (without leading #) for board messages, or the sender's
   * username for direct messages.
   */
  target: string;
  /** True when the message arrived from a board (group), false for DMs. */
  isBoard: boolean;
  senderId: string;
  senderUsername: string;
  text: string;
  timestamp: number;
}

