/**
 * Account resolution for the PulseBoard channel plugin.
 *
 * Reads config from channels.pulseboard, merges per-account overrides, and
 * falls back to environment variables (PULSEBOARD_API_TOKEN, PULSEBOARD_SERVER_URL).
 */

import {
  DEFAULT_ACCOUNT_ID,
  listCombinedAccountIds,
  resolveMergedAccountConfig,
  type OpenClawConfig,
} from "openclaw/plugin-sdk/account-resolution";
import type {
  PulseBoardChannelConfig,
  ResolvedPulseBoardAccount,
} from "./types.js";

function getChannelConfig(cfg: OpenClawConfig): PulseBoardChannelConfig | undefined {
  return cfg?.channels?.["pulseboard"] as PulseBoardChannelConfig | undefined;
}

function resolveImplicitAccountId(channelCfg: PulseBoardChannelConfig): string | undefined {
  const hasToken = Boolean(
    channelCfg.apiToken?.trim() || process.env.PULSEBOARD_API_TOKEN?.trim(),
  );
  const hasUrl = Boolean(
    channelCfg.serverUrl?.trim() || process.env.PULSEBOARD_SERVER_URL?.trim(),
  );
  return hasToken || hasUrl ? DEFAULT_ACCOUNT_ID : undefined;
}

/**
 * List all configured PulseBoard account IDs.
 * Returns ["default"] when a base config or env vars are present, plus any
 * named accounts defined under channels.pulseboard.accounts.
 */
export function listPulseBoardAccountIds(cfg: OpenClawConfig): string[] {
  const channelCfg = getChannelConfig(cfg);
  if (!channelCfg) {
    return [];
  }
  return listCombinedAccountIds({
    configuredAccountIds: Object.keys(channelCfg.accounts ?? {}),
    implicitAccountId: resolveImplicitAccountId(channelCfg),
  });
}

/**
 * Resolve a PulseBoard account by ID with all defaults applied.
 * Falls back to PULSEBOARD_API_TOKEN / PULSEBOARD_SERVER_URL env vars for
 * the "default" account.
 */
export function resolvePulseBoardAccount(
  cfg: OpenClawConfig,
  accountId?: string | null,
): ResolvedPulseBoardAccount {
  const channelCfg = getChannelConfig(cfg) ?? {};
  const id = accountId || DEFAULT_ACCOUNT_ID;

  const merged = resolveMergedAccountConfig<Record<string, unknown> & PulseBoardChannelConfig>({
    channelConfig: channelCfg as Record<string, unknown> & PulseBoardChannelConfig,
    accounts: channelCfg.accounts as
      | Record<string, Partial<Record<string, unknown> & PulseBoardChannelConfig>>
      | undefined,
    accountId: id,
  });

  const envApiToken = id === DEFAULT_ACCOUNT_ID ? (process.env.PULSEBOARD_API_TOKEN?.trim() ?? "") : "";
  const envServerUrl = id === DEFAULT_ACCOUNT_ID ? (process.env.PULSEBOARD_SERVER_URL?.trim() ?? "") : "";

  const apiToken = ((merged.apiToken as string | undefined)?.trim() ?? envApiToken);
  // Strip trailing slash so callers can safely append paths with /
  const serverUrl = ((merged.serverUrl as string | undefined)?.trim() ?? envServerUrl).replace(
    /\/+$/,
    "",
  );
  const configured = Boolean(apiToken && serverUrl);

  return {
    accountId: id,
    enabled: (merged.enabled as boolean | undefined) ?? true,
    configured,
    apiToken,
    serverUrl,
    dmPolicy:
      (merged.dmPolicy as ResolvedPulseBoardAccount["dmPolicy"] | undefined) ?? "pairing",
    allowFrom: (merged.allowFrom as Array<string | number> | undefined) ?? [],
    boards: (merged.boards as string[] | undefined) ?? [],
    groupPolicy: (merged.groupPolicy as "allowlist" | "open" | undefined) ?? "allowlist",
  };
}

/** List all enabled PulseBoard accounts with their resolved config. */
export function listEnabledPulseBoardAccounts(cfg: OpenClawConfig): ResolvedPulseBoardAccount[] {
  return listPulseBoardAccountIds(cfg)
    .map((accountId) => resolvePulseBoardAccount(cfg, accountId))
    .filter((account) => account.enabled);
}

