input.content:
/**
 * PulseBoard channel plugin for OpenClaw.
 *
 * PulseBoard is a real-time bulletin board messaging platform where users post
 * messages to named "boards" (group chats) and can also send direct messages.
 * Authentication uses a per-account API token against a configured server URL.
 *
 * Boards are addressed as "#board-name" (group targets) and direct messages
 * are addressed by plain username (e.g. "alice").
 *
 * Text chunk limit: 4000 characters (PulseBoard's per-post character cap).
 */

import type { OpenClawConfig } from "openclaw/plugin-sdk/account-resolution";
import {
  createHybridChannelConfigAdapter,
  createScopedDmSecurityResolver,
} from "openclaw/plugin-sdk/channel-config-helpers";
import { waitUntilAbort } from "openclaw/plugin-sdk/channel-lifecycle";
import {
  composeWarningCollectors,
  createConditionalWarningCollector,
  projectAccountWarningCollector,
} from "openclaw/plugin-sdk/channel-policy";
import { attachChannelToResult } from "openclaw/plugin-sdk/channel-send-result";
import { createChatChannelPlugin, type ChannelPlugin } from "openclaw/plugin-sdk/core";
import { createEmptyChannelDirectoryAdapter } from "openclaw/plugin-sdk/directory-runtime";
import { DEFAULT_ACCOUNT_ID } from "openclaw/plugin-sdk/setup";
import {
  listPulseBoardAccountIds,
  resolvePulseBoardAccount,
} from "./accounts.js";
import { PulseBoardChannelConfigSchema } from "./config-schema.js";
import { pulseBoardSetupAdapter, pulseBoardSetupWizard } from "./setup-surface.js";
import type { ResolvedPulseBoardAccount } from "./types.js";

const CHANNEL_ID = "pulseboard";
const PAIRING_APPROVED_MESSAGE = "OpenClaw: your access has been approved.";

/**
 * PulseBoard text chunk limit in characters.
 * PulseBoard imposes a 4000-character cap on individual posts.
 */
const PULSEBOARD_TEXT_CHUNK_LIMIT = 4000;

// ---------------------------------------------------------------------------
// Target normalization
// ---------------------------------------------------------------------------

/**
 * Normalize a PulseBoard board name: strip leading # characters and lowercase.
 * Board targets are always returned with a leading # prefix.
 */
function normalizeBoardName(raw: string): string {
  return raw.replace(/^#+/, "").toLowerCase().trim();
}

/**
 * Normalize a PulseBoard messaging target.
 * - Targets starting with "#" are boards: returned as "#board-name".
 * - All other targets are treated as direct-message usernames (lowercased).
 * Returns undefined for empty or whitespace-only inputs.
 */
export function normalizePulseBoardTarget(target: string): string | undefined {
  const trimmed = target.trim();
  if (!trimmed) return undefined;
  if (trimmed.startsWith("#")) {
    const name = normalizeBoardName(trimmed);
    return name ? `#${name}` : undefined;
  }
  return trimmed.toLowerCase();
}

/** Returns true when the input looks like a PulseBoard board or username ID. */
export function looksLikePulseBoardId(id: string): boolean {
  const trimmed = id?.trim();
  if (!trimmed) return false;
  // Board: starts with #
  if (trimmed.startsWith("#")) return trimmed.length > 1;
  // Username: alphanumeric, dots, hyphens, underscores
  return /^[\w.-]+$/.test(trimmed);
}

/** Returns true when the normalized target refers to a board (group) chat. */
export function isBoardTarget(target: string): boolean {
  return target.startsWith("#");
}

// ---------------------------------------------------------------------------
// Outbound delivery
// ---------------------------------------------------------------------------

/**
 * Split text into chunks no larger than `limit` characters.
 * Attempts to break at newline boundaries within the last quarter of the
 * limit to avoid splitting mid-sentence.
 */
function chunkPulseBoardText(text: string, limit: number): string[] {
  if (text.length <= limit) return [text];
  const chunks: string[] = [];
  let remaining = text;
  while (remaining.length > 0) {
    if (remaining.length <= limit) {
      chunks.push(remaining);
      break;
    }
    const slice = remaining.slice(0, limit);
    // Prefer a newline split in the last 25% of the window
    const searchFrom = Math.floor(limit * 0.75);
    const lastNewline = slice.lastIndexOf("\n", limit - 1);
    const splitAt = lastNewline >= searchFrom ? lastNewline + 1 : limit;
    chunks.push(remaining.slice(0, splitAt));
    remaining = remaining.slice(splitAt);
  }
  return chunks;
}

/**
 * Send a text message to a PulseBoard target (board or direct message).
 *
 * In production this would POST to:
 *   {serverUrl}/api/v1/messages
 * with Authorization: Bearer {apiToken} and a JSON body of { target, text }.
 *
 * This implementation is stubbed for the fictional PulseBoard platform and
 * returns a synthetic message ID without performing a real network call.
 */
async function sendPulseBoardMessage(params: {
  serverUrl: string;
  apiToken: string;
  target: string;
  text: string;
}): Promise<string> {
  // Real implementation sketch:
  //   const res = await fetch(`${params.serverUrl}/api/v1/messages`, {
  //     method: "POST",
  //     headers: {
  //       Authorization: `Bearer ${params.apiToken}`,
  //       "Content-Type": "application/json",
  //     },
  //     body: JSON.stringify({ target: params.target, text: params.text }),
  //   });
  //   const json = await res.json();
  //   return json.messageId as string;

  // Stubbed: return a synthetic message ID.
  const messageId = `pb-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
  return messageId;
}

// ---------------------------------------------------------------------------
// Config adapter
// ---------------------------------------------------------------------------

const pulseBoardConfigAdapter = createHybridChannelConfigAdapter<ResolvedPulseBoardAccount>({
  sectionKey: CHANNEL_ID,
  listAccountIds: listPulseBoardAccountIds,
  resolveAccount: resolvePulseBoardAccount,
  defaultAccountId: () => DEFAULT_ACCOUNT_ID,
  clearBaseFields: ["apiToken", "serverUrl", "dmPolicy", "allowFrom", "boards", "groupPolicy"],
  resolveAllowFrom: (account) => account.allowFrom,
  formatAllowFrom: (allowFrom) =>
    allowFrom.map((entry) => String(entry).trim().toLowerCase()).filter(Boolean),
});

// ---------------------------------------------------------------------------
// Security / DM policy
// ---------------------------------------------------------------------------

const resolvePulseBoardDmPolicy = createScopedDmSecurityResolver<ResolvedPulseBoardAccount>({
  channelKey: CHANNEL_ID,
  resolvePolicy: (account) => account.dmPolicy,
  resolveAllowFrom: (account) => account.allowFrom,
  policyPathSuffix: "dmPolicy",
  defaultPolicy: "pairing",
  approveHint: "openclaw pairing approve pulseboard <code>",
  normalizeEntry: (raw) => raw.toLowerCase().trim(),
});

type PulseBoardWarningContext = {
  cfg: OpenClawConfig;
  account: ResolvedPulseBoardAccount;
};

const collectPulseBoardAccountWarnings =
  createConditionalWarningCollector<ResolvedPulseBoardAccount>(
    (account) =>
      !account.apiToken &&
      "- PulseBoard: apiToken is not configured; the bot cannot authenticate.",
    (account) =>
      !account.serverUrl &&
      "- PulseBoard: serverUrl is not configured; the bot cannot connect.",
    (account) =>
      account.dmPolicy === "open" &&
      '- PulseBoard: dmPolicy="open" allows any user to message the bot. Consider "allowlist" for production use.',
    (account) =>
      account.groupPolicy === "open" &&
      '- PulseBoard: groupPolicy="open" allows messages from any board member without an allowlist.',
    (account) =>
      account.dmPolicy === "allowlist" &&
      account.allowFrom.length === 0 &&
      '- PulseBoard: dmPolicy="allowlist" with empty allowFrom blocks all DM senders. Add users or switch to "pairing".',
  );

// ---------------------------------------------------------------------------
// Plugin definition
// ---------------------------------------------------------------------------

export const pulseBoardPlugin = createChatChannelPlugin({
  base: {
    id: CHANNEL_ID,
    meta: {
      id: CHANNEL_ID,
      label: "PulseBoard",
      selectionLabel: "PulseBoard (API Token)",
      detailLabel: "PulseBoard",
      docsPath: "/channels/pulseboard",
      blurb: "Real-time bulletin board messaging with named boards and direct messages.",
      order: 95,
    },
    capabilities: {
      chatTypes: ["direct" as const, "group" as const],
      media: false,
      threads: false,
      reactions: false,
      edit: false,
      unsend: false,
      reply: false,
      effects: false,
      blockStreaming: false,
    },
    reload: { configPrefixes: [`channels.${CHANNEL_ID}`] },
    configSchema: PulseBoardChannelConfigSchema,
    setup: pulseBoardSetupAdapter,
    setupWizard: pulseBoardSetupWizard,
    config: {
      ...pulseBoardConfigAdapter,
      isConfigured: (account) => account.configured,
      describeAccount: (account) => ({
        accountId: account.accountId,
        configured: account.configured,
        serverUrl: account.serverUrl,
        dmPolicy: account.dmPolicy,
        groupPolicy: account.groupPolicy,
        boardCount: account.boards.length,
      }),
    },
    messaging: {
      normalizeTarget: normalizePulseBoardTarget,
      targetResolver: {
        looksLikeId: looksLikePulseBoardId,
        hint: "<#board-name|username>",
      },
    },
    directory: createEmptyChannelDirectoryAdapter(),
    gateway: {
      startAccount: async (ctx) => {
        const { cfg, accountId, log, abortSignal } = ctx;
        const account = resolvePulseBoardAccount(cfg, accountId);

        if (!account.configured) {
          log?.warn?.(
            `[${accountId}] PulseBoard is not configured (need apiToken and serverUrl ` +
              `in channels.pulseboard). Waiting for config update.`,
          );
          // Hold open until config changes trigger a reload.
          return waitUntilAbort(abortSignal);
        }

        log?.info?.(
          `[${accountId}] Starting PulseBoard connection to ${account.serverUrl}`,
        );

        // Production implementation would:
        // 1. Open a WebSocket to {serverUrl}/api/v1/events?token={apiToken}.
        // 2. Subscribe to board streams for each entry in account.boards.
        // 3. On each inbound message, dispatch through ctx.runtime.dispatch()
        //    with the normalized target, sender, and text.
        // 4. Reconnect on disconnect with exponential back-off, respecting
        //    abortSignal for clean shutdown.

        return waitUntilAbort(abortSignal, () => {
          log?.info?.(`[${accountId}] PulseBoard connection closed`);
        });
      },
    },
  },
  pairing: {
    text: {
      idLabel: "pulseBoardUser",
      message: PAIRING_APPROVED_MESSAGE,
      normalizeAllowEntry: (entry: string) => entry.toLowerCase().trim(),
      notify: async ({ cfg, id, message }) => {
        const account = resolvePulseBoardAccount(cfg as OpenClawConfig);
        if (!account.configured) return;
        // Send the pairing approval message as a DM to the requesting user.
        await sendPulseBoardMessage({
          serverUrl: account.serverUrl,
          apiToken: account.apiToken,
          target: id.toLowerCase().trim(),
          text: message,
        });
      },
    },
  },
  security: {
    resolveDmPolicy: resolvePulseBoardDmPolicy,
    collectWarnings: composeWarningCollectors(
      projectAccountWarningCollector<ResolvedPulseBoardAccount, PulseBoardWarningContext>(
        collectPulseBoardAccountWarnings,
      ),
    ),
  },
  outbound: {
    base: {
      deliveryMode: "direct" as const,
      chunker: chunkPulseBoardText,
      chunkerMode: "markdown" as const,
      textChunkLimit: PULSEBOARD_TEXT_CHUNK_LIMIT,
    },
    attachedResults: {
      channel: CHANNEL_ID,
      sendText: async ({ cfg, to, text, accountId }) => {
        const account = resolvePulseBoardAccount(cfg as OpenClawConfig, accountId);
        if (!account.configured) {
          throw new Error(
            `PulseBoard account "${accountId ?? DEFAULT_ACCOUNT_ID}" is not configured.`,
          );
        }
        const target = normalizePulseBoardTarget(to) ?? to;
        const messageId = await sendPulseBoardMessage({
          serverUrl: account.serverUrl,
          apiToken: account.apiToken,
          target,
          text,
        });
        return attachChannelToResult(CHANNEL_ID, { messageId, chatId: to });
      },
      sendMedia: async ({ cfg, to, text, mediaUrl, accountId }) => {
        const account = resolvePulseBoardAccount(cfg as OpenClawConfig, accountId);
        if (!account.configured) {
          throw new Error(
            `PulseBoard account "${accountId ?? DEFAULT_ACCOUNT_ID}" is not configured.`,
          );
        }
        const target = normalizePulseBoardTarget(to) ?? to;
        // PulseBoard does not support native file uploads in v1; include
        // the media URL as a plain link appended to the message body.
        const body = mediaUrl ? (text ? `${text}\n\n${mediaUrl}` : mediaUrl) : (text ?? "");
        const messageId = await sendPulseBoardMessage({
          serverUrl: account.serverUrl,
          apiToken: account.apiToken,
          target,
          text: body,
        });
        return attachChannelToResult(CHANNEL_ID, { messageId, chatId: to });
      },
    },
  },
}) as ChannelPlugin<ResolvedPulseBoardAccount>;

