];

const PULSEBOARD_ALLOW_FROM_HELP_LINES = [
  "Allowlist PulseBoard DMs by username.",
  "Examples:",
  "- alice",
  "- bob",
  "Multiple entries: comma-separated.",
  `Docs: ${formatDocsLink("/channels/pulseboard", "channels/pulseboard")}`,
];

// ---------------------------------------------------------------------------
// Config helpers
// ---------------------------------------------------------------------------

function getChannelConfig(cfg: OpenClawConfig): PulseBoardChannelConfig {
  return (cfg.channels?.[channel] as PulseBoardChannelConfig | undefined) ?? {};
}

function getRawAccountConfig(
  cfg: OpenClawConfig,
  accountId: string,
): PulseBoardChannelConfig {
  const channelConfig = getChannelConfig(cfg);
  if (accountId === DEFAULT_ACCOUNT_ID) {
    return channelConfig;
  }
  return channelConfig.accounts?.[accountId] ?? {};
}

/**
 * Immutably patch the config for a given PulseBoard account.
 * For the default account, merges directly into channels.pulseboard.
 * For named accounts, merges into channels.pulseboard.accounts[accountId].
 */
function patchPulseBoardAccountConfig(params: {
  cfg: OpenClawConfig;
  accountId: string;
  patch: Record<string, unknown>;
  clearFields?: string[];
  enabled?: boolean;
}): OpenClawConfig {
  const channelConfig = getChannelConfig(params.cfg);

  if (params.accountId === DEFAULT_ACCOUNT_ID) {
    const next = { ...channelConfig } as Record<string, unknown>;
    for (const field of params.clearFields ?? []) {
      delete next[field];
    }
    return {
      ...params.cfg,
      channels: {
        ...params.cfg.channels,
        [channel]: {
          ...next,
          ...(params.enabled ? { enabled: true } : {}),
          ...params.patch,
        },
      },
    };
  }

  const nextAccounts = { ...(channelConfig.accounts ?? {}) } as Record<
    string,
    Record<string, unknown>
  >;
  const nextAccount = { ...(nextAccounts[params.accountId] ?? {}) };
  for (const field of params.clearFields ?? []) {
    delete nextAccount[field];
  }
  nextAccounts[params.accountId] = {
    ...nextAccount,
    ...(params.enabled ? { enabled: true } : {}),
    ...params.patch,
  };
  return {
    ...params.cfg,
    channels: {
      ...params.cfg.channels,
      [channel]: {
        ...channelConfig,
        ...(params.enabled ? { enabled: true } : {}),
        accounts: nextAccounts,
      },
    },
  };
}

function isPulseBoardConfigured(cfg: OpenClawConfig, accountId: string): boolean {
  return resolvePulseBoardAccount(cfg, accountId).configured;
}

function validateServerUrl(value: string): string | undefined {
  const trimmed = value.trim();
  if (!trimmed) return "PulseBoard server URL is required.";
  try {
    const parsed = new URL(trimmed);
    if (parsed.protocol !== "http:" && parsed.protocol !== "https:") {
      return "Server URL must use http:// or https://.";
    }
  } catch {
    return "Server URL must be a valid URL (e.g. https://pb.example.com).";
  }
  return undefined;
}

/** Normalize a PulseBoard username for the allowlist: lowercase, strip prefix. */
function parsePulseBoardAllowEntry(value: string): string | null {
  const cleaned = value.replace(/^pulseboard:/i, "").trim().toLowerCase();
  // Usernames must be non-empty and contain only word characters, dots, hyphens
  return cleaned && /^[\w.-]+$/.test(cleaned) ? cleaned : null;
}

function resolveExistingAllowFrom(cfg: OpenClawConfig, accountId: string): string[] {
  return resolvePulseBoardAccount(cfg, accountId).allowFrom.map((e) =>
    String(e).trim().toLowerCase(),
  );
}

// ---------------------------------------------------------------------------
// Setup adapter (CLI --configure path)
// ---------------------------------------------------------------------------

export const pulseBoardSetupAdapter: ChannelSetupAdapter = {
  resolveAccountId: ({ accountId }) => normalizeAccountId(accountId) ?? DEFAULT_ACCOUNT_ID,
  validateInput: ({ input }) => {
    if (!input.apiToken?.trim()) {
      return "PulseBoard requires --token (API token).";
    }
    if (!input.serverUrl?.trim()) {
      return "PulseBoard requires --url (server URL).";
    }
    return validateServerUrl(input.serverUrl.trim()) ?? null;
  },
  applyAccountConfig: ({ cfg, accountId, input }) =>
    patchPulseBoardAccountConfig({
      cfg,
      accountId,
      enabled: true,
      patch: {
        apiToken: input.apiToken?.trim(),
        serverUrl: input.serverUrl?.trim().replace(/\/+$/, ""),
      },
    }),
};

// ---------------------------------------------------------------------------
// Setup wizard (interactive path)
// ---------------------------------------------------------------------------

export const pulseBoardSetupWizard: ChannelSetupWizard = {
  channel,
  status: createStandardChannelSetupStatus({
    channelLabel: "PulseBoard",
    configuredLabel: "configured",
    unconfiguredLabel: "needs API token + server URL",
    configuredHint: "configured",
    unconfiguredHint: "needs API token + server URL",
    configuredScore: 1,
    unconfiguredScore: 0,
    includeStatusLine: true,
    resolveConfigured: ({ cfg }) =>
      listPulseBoardAccountIds(cfg).some((accountId) =>
        isPulseBoardConfigured(cfg, accountId),
      ),
  }),
  introNote: {
    title: "PulseBoard setup",
    lines: PULSEBOARD_SETUP_HELP_LINES,
  },
  credentials: [
    {
      inputKey: "apiToken",
      providerHint: channel,
      credentialLabel: "API token",
      preferredEnvVar: "PULSEBOARD_API_TOKEN",
      helpTitle: "PulseBoard API token",
      helpLines: PULSEBOARD_SETUP_HELP_LINES,
      envPrompt: "PULSEBOARD_API_TOKEN detected. Use env var?",
      keepPrompt: "PulseBoard API token already configured. Keep it?",
      inputPrompt: "Enter PulseBoard API token",
      allowEnv: ({ accountId }) => accountId === DEFAULT_ACCOUNT_ID,
      inspect: ({ cfg, accountId }) => {
        const account = resolvePulseBoardAccount(cfg, accountId);
        const raw = getRawAccountConfig(cfg, accountId);
        return {
          accountConfigured: isPulseBoardConfigured(cfg, accountId),
          hasConfiguredValue: Boolean(raw.apiToken?.trim()),
          resolvedValue: account.apiToken || undefined,
          envValue:
            accountId === DEFAULT_ACCOUNT_ID
              ? process.env.PULSEBOARD_API_TOKEN?.trim() || undefined
              : undefined,
        };
      },
      applyUseEnv: async ({ cfg, accountId }) =>
        patchPulseBoardAccountConfig({
          cfg,
          accountId,
          enabled: true,
          clearFields: ["apiToken"],
          patch: {},
        }),
      applySet: async ({ cfg, accountId, resolvedValue }) =>
        patchPulseBoardAccountConfig({
          cfg,
          accountId,
          enabled: true,
          patch: { apiToken: resolvedValue },
        }),
    },
  ],
  textInputs: [
    {
      inputKey: "serverUrl",
      message: "PulseBoard server URL",
      placeholder: "https://pb.example.com",
      helpTitle: "PulseBoard server URL",
      helpLines: [
        "The base URL of your PulseBoard server.",
        "Example: https://pb.example.com",
        "The URL must use http:// or https://.",
      ],
      currentValue: ({ cfg, accountId }) =>
        getRawAccountConfig(cfg, accountId).serverUrl?.trim() || undefined,
      keepPrompt: (value) => `Server URL set (${value}). Keep it?`,
      validate: ({ value }) => validateServerUrl(value),
      applySet: async ({ cfg, accountId, value }) =>
        patchPulseBoardAccountConfig({
          cfg,
          accountId,
          enabled: true,
          patch: { serverUrl: value.trim().replace(/\/+$/, "") },
        }),
    },
  ],
  allowFrom: createAllowFromSection({
    helpTitle: "PulseBoard allowlist",
    helpLines: PULSEBOARD_ALLOW_FROM_HELP_LINES,
    message: "Allowed PulseBoard usernames",
    placeholder: "alice, bob",
    invalidWithoutCredentialNote: "Use a valid PulseBoard username (alphanumeric, dots, hyphens).",
    parseInputs: splitSetupEntries,
    parseId: parsePulseBoardAllowEntry,
    apply: async ({ cfg, accountId, allowFrom }) =>
      patchPulseBoardAccountConfig({
        cfg,
        accountId,
        enabled: true,
        patch: {
          dmPolicy: "allowlist",
          allowFrom: mergeAllowFromEntries(resolveExistingAllowFrom(cfg, accountId), allowFrom),
        },
      }),
  }),
  completionNote: {
    title: "PulseBoard next steps",
    lines: [
      "Restart the gateway and verify: openclaw channels status --probe",
      "To listen on boards (group chats), add board names to channels.pulseboard.boards.",
      "Example: channels.pulseboard.boards = [\"general\", \"ops\"]",
      "To tighten board access, set channels.pulseboard.groupPolicy=\"allowlist\".",
      `Docs: ${formatDocsLink("/channels/pulseboard", "channels/pulseboard")}`,
    ],
  },
  disable: (cfg) => setSetupChannelEnabled(cfg, channel, false),
};

